  "statistiche_core": {
    "forza": {"valore": 15, "modificatore": 2},
    "destrezza": {"valore": 10, "modificatore": 0},
    "costituzione": {"valore": 14, "modificatore": 2},
    "intelligenza": {"valore": 8, "modificatore": -1},
