    "carisma": {"valore": 10, "modificatore": 0}
  },
  "combattimento": {
    "hp_massimi": 25,
    "hp_attuali": 25,
    "classe_armatura": 16,
    "iniziativa": 0,
    "velocita": 9
  },
  "equipaggiamento": {
    "armi":[{"nome": "Spada Lunga", "bonus_attacco": 4, "danno": "1d8+2", "tipo": "Tagliente"}],
